];
SigninLogs
//| where TimeGenerated >= ago(5m)  // Ajusta el rango de tiempo según tu necesidad
| where UserPrincipalName in (usuarios_permitidos
| project UserPrincipalName) // Filtrar usuarios permitidos
| extend ParsedDeviceDetail = parse_json(DeviceDetail) // Convertir DeviceDetail a JSON
| extend ExtractedDeviceId = tostring(ParsedDeviceDetail.deviceId) // Extraer el DeviceId
| join kind=leftouter usuarios_permitidos on UserPrincipalName // Relacionar con la tabla permitidos
| extend CoincideDeviceId = iff(ExtractedDeviceId == deviceId, "Sí", "No") // Comparar DeviceId
| where CoincideDeviceId == "No" or isnull(ExtractedDeviceId) // Si no coincide o está vacío
| project TimeGenerated, UserPrincipalName, ExtractedDeviceId, deviceId, IPAddress, AuthenticationDetails, DeviceDetail
